#include <bits/stdc++.h>
#define zrq0331
#define int long long
using namespace std;
struct edge {
    int u, v, o;
}e[150000];
int fa[200000], n, m, k;
int tot, tot1, tot2;
int res;
int ans[200000][3];
void init () {
    for (int i = 1; i <= n; i++) {
    	fa[i]=i;
	}
}
int fid (int x) {
	if (x != fa[x]) {
		fa[x] = fid(fa[x]);
	}
	return fa[x];
}
bool same (int x,int y) {
	return fid (x) == fid (y);
}
void Union (int x, int y) {
	int a = fid(x), b = fid(y);
	if (a != b) {
		fa[b] = a;
	}
}
signed main(){
	cin >> n >> m >> k; 
    init ();
    for (int i = 1; i <= m; i++){
        cin >> e[i].u;
        cin >> e[i].v;
        cin >> e[i].o;
        if (e[i].o) {
        	if (!same (e[i].u, e[i].v)) {
        		Union (e[i].u, e[i].v);
        		res++;
			} 
		}
    }
    for (int i = 1; i <= m; i++){
        if (!e[i].o) {
            int x = e[i].u, y = e[i].v;
            if (!same (x, y)) {
            	Union (x, y);
            	ans[++tot][0] = x;
            	ans[tot][1] = y;
            	ans[tot][2] = 0;
            	res++;
			}
            if (tot1 > k) {
                cout << "no solution";
                return 0;
            }
        }
    }
    tot1 = tot;
    if (res != n - 1) {
        cout << "no solution";
        return 0;
    }
    init();
    for (int i = 1; i <= m; i++){
        if (!e[i].o){
            int x = e[i].u;
			int y = e[i].v;
            if (!same (x, y)) {
            	Union (x, y);
			}
        }
    }
    for (int i = 1; i <= m; i++){
        if (e[i].o){
            int x =e[i].u;
			int y=e[i].v;
            if (!same (x, y)) {
            	Union (x, y);
            	ans[++tot][0] = e[i].u;
            	ans[tot][1] = e[i].v;
            	ans[tot][2] = 1;
            	tot2++;
			}
            if (tot2 > n - 1 - k){
                cout << "no solution";
                return 0;
            }
        }
    }
    init ();
    for (int i = 1; i <= tot; i++){
        int x = ans[i][0], y = ans[i][1];
        Union (x, y);
    }
    for (int i = 1; i <= m; i++){
        int x = e[i].u, y = e[i].v;
        if (e[i].o && tot2 < n - 1 - k && !same (x, y)) {
            Union (x, y);
            ans[++tot][0] = x;
            ans[tot][1] = y;
			ans[tot][2] = 1;
            tot2++;
        }
        if (!e[i].o && tot1 < k && !same (x, y)){
            Union(x,y);
            ans[++tot][0] = x;
			ans[tot][1] = y;
			ans[tot][2] = 0;
            tot1++;
        }
    }
    for (int i = 1; i < n; i++) {
    	cout << ans[i][0] << ' ' << ans[i][1] << ' ' << ans[i][2] << '\n';
	}
    return 0;
}
